// Interface: defines the contract
interface PaymentProcessor {
  processPayment(amount: number): boolean;
  getFeePercentage(): number;
}
// First implementation: Credit Card processing
class CreditCardProcessor implements PaymentProcessor {
  processPayment(amount: number): boolean {
    console.log(`Processing credit card charge of $${amount}`);
    return true; // Assume success
  }
  getFeePercentage(): number {
    return 2.9; // 2.9% fee
  }
}
// Second implementation: PayPal processing
class PayPalProcessor implements PaymentProcessor {
  processPayment(amount: number): boolean {
    console.log(`Processing PayPal payment of $${amount}`);
    return true;
  }
  getFeePercentage(): number {
    return 3.5; // 3.5% fee
  }
}
// Function depends on interface, not concrete class
function charge(processor: PaymentProcessor, amount: number): void {
  const fee: number = amount * (processor.getFeePercentage() / 100);
  processor.processPayment(amount + fee);
}
charge(new CreditCardProcessor(), 100);
// Expected: Processing credit card charge of $102.9
